import React, { useState } from 'react';
import { View, Text, Button } from 'react-native';
import OAuth2 from 'oauth2';

const CLIENT_ID = 'your_client_id';
const CLIENT_SECRET = 'your_client_secret';
const REDIRECT_URI = 'http://localhost:3000/callback';
const SCOPE = 'read write';

function App() {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  const oauth2 = new OAuth2({
    client_id: CLIENT_ID,
    client_secret: CLIENT_SECRET,
    redirect_uri: REDIRECT_URI,
    scope: SCOPE,
  });

  async function handleLogin() {
    const authUrl = oauth2.authorizeURL();
    console.log(authUrl);
  }

  async function handleCallback(url) {
    const token = await oauth2.tokenFromCode(url);
    setAccessToken(token.access_token);
    setRefreshToken(token.refresh_token);
  }

  async function refreshTokens() {
    if (refreshToken) {
      const token = await oauth2.refreshToken(refreshToken);
      setAccessToken(token.access_token);
      setRefreshToken(token.refresh_token);
    }
  }

  return (
    <View>
      <Text>OAuth2 Authentication</Text>
      <Button title="Login" onPress={handleLogin} />
      {accessToken && (
        <>
          <Text>Access Token: {accessToken}</Text>
          <Button title="Refresh Tokens" onPress={refreshTokens} />
        </>
      )}
    </View>
  );
}

export default App;